import re,glob
labels=set(); uses=set()
for f in glob.glob('blueprint/src/chapters/*.tex'):
    t=open(f).read()
    for m in re.findall(r'\\label\{([^}]+)\}',t): labels.add(m)
    for m in re.findall(r'\\uses\{([^}]+)\}',t):
        for u in re.split(r'[,\s]+',m):
            if u.strip(): uses.add(u.strip())
broken=sorted(u for u in uses if u not in labels)
print("broken uses (no matching label):", broken if broken else "NONE")
PY
